css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { min-height: 100vh; background: #030b18; font-family: -apple-system, BlinkMacSystemFont, sans-serif; display: flex; align-items: center; justify-content: center; color: white; padding: 20px; }
.app { width: 100%; max-width: 480px; text-align: center; }
.progress-dots { display: flex; justify-content: center; gap: 8px; margin-bottom: 40px; }
.dot { width: 8px; height: 8px; border-radius: 4px; background: rgba(255,255,255,0.2); transition: all 0.3s; } .dot.active { width: 24px; background: #06b6d4; }
.slides { min-height: 440px; display: flex; align-items: center; justify-content: center; }
.slide { width: 100%; animation: fadeIn 0.4s ease; }
@keyframes fadeIn { from{opacity:0;transform:translateY(10px)} to{opacity:1;transform:translateY(0)} }
.slide-emoji { font-size: 80px; margin-bottom: 24px; }
.slide-title { font-size: 32px; font-weight: 900; margin-bottom: 14px; line-height: 1.2; }
.slide-desc { color: #6b7280; font-size: 16px; line-height: 1.75; margin-bottom: 28px; max-width: 380px; margin-left: auto; margin-right: auto; }
.slide-visual { background: rgba(6,182,212,0.08); border: 1px solid rgba(6,182,212,0.2); border-radius: 20px; padding: 24px; margin-bottom: 0; }
.setup-form { display: flex; flex-direction: column; gap: 14px; text-align: left; }
.setup-form label { font-size: 13px; font-weight: 700; color: #06b6d4; letter-spacing: 1px; display: block; margin-bottom: 6px; }
.setup-form input, .setup-form select { width: 100%; height: 48px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.12); background: rgba(255,255,255,0.06); color: white; padding: 0 16px; font-size: 15px; outline: none; } input:focus, select:focus { border-color: #06b6d4; }
.feature-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; }
.feature-item { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 14px; padding: 16px; text-align: left; cursor: pointer; transition: all 0.2s; } .feature-item:hover, .feature-item.selected { border-color: #06b6d4; background: rgba(6,182,212,0.1); }
.fi-emoji { font-size: 24px; margin-bottom: 8px; } .fi-title { font-size: 14px; font-weight: 700; margin-bottom: 2px; } .fi-desc { font-size: 12px; color: #6b7280; }
.success-checks { display: flex; flex-direction: column; gap: 10px; margin-top: 16px; }
.sc-item { display: flex; align-items: center; gap: 12px; padding: 12px 16px; background: rgba(34,197,94,0.08); border: 1px solid rgba(34,197,94,0.2); border-radius: 12px; font-size: 14px; }
.sc-check { width: 24px; height: 24px; border-radius: 50%; background: #22c55e; display: flex; align-items: center; justify-content: center; font-size: 12px; flex-shrink: 0; }
.controls { display: flex; justify-content: space-between; align-items: center; margin-top: 32px; }
.back-btn { padding: 14px 24px; border-radius: 14px; border: 1px solid rgba(255,255,255,0.15); background: transparent; color: white; font-weight: 600; cursor: pointer; }
.next-btn { padding: 14px 32px; border-radius: 14px; border: none; background: linear-gradient(135deg, #06b6d4, #0891b2); color: white; font-weight: 800; font-size: 15px; cursor: pointer; transition: opacity 0.2s; } .next-btn:hover { opacity: 0.9; }

