const steps = [
  { emoji:'👋', title:'Nova\'ya Hoş Geldin!', desc:'Projelerini yönetmek, ekibinle iletişim kurmak ve her şeyi organize etmek için en iyi platform.', type:'intro' },
  { emoji:'👤', title:'Profili Oluştur', desc:'Seni tanımamız için birkaç bilgi paylaş.', type:'setup' },
  { emoji:'🎯', title:'Ne Kullanacaksın?', desc:'Kullanmak istediğin özellikleri seç.', type:'features' },
  { emoji:'🎉', title:'Hazırsın!', desc:'Her şey ayarlandı. Hemen başlayabilirsin!', type:'success' }
];
const features = [
  {emoji:'📋', title:'Görev Yönetimi', desc:'Kanban ve liste'},
  {emoji:'👥', title:'Ekip İşbirliği', desc:'Gerçek zamanlı'},
  {emoji:'📊', title:'Analitik', desc:'Detaylı raporlar'},
  {emoji:'🔗', title:'Entegrasyonlar', desc:'200+ uygulama'}
];
let current = 0;
function renderDots() {
  document.getElementById('dots').innerHTML = steps.map((_,i) => `<div class='dot ${i===current?'active':''}'></div>`).join('');
}
function renderSlide() {
  const s = steps[current];
  let content = '';
  if (s.type === 'intro') content = `<div class='slide'><div class='slide-emoji'>${s.emoji}</div><div class='slide-title'>${s.title}</div><div class='slide-desc'>${s.desc}</div><div class='slide-visual'><div style='font-size:14px;color:#06b6d4;font-weight:700;margin-bottom:12px'>✦ NELER SUNUYORUZ</div><div style='display:grid;grid-template-columns:1fr 1fr;gap:8px;text-align:left'><div style='font-size:13px;color:#e2e8f0'>✓ Sınırsız proje</div><div style='font-size:13px;color:#e2e8f0'>✓ Ekip işbirliği</div><div style='font-size:13px;color:#e2e8f0'>✓ Gerçek zamanlı sync</div><div style='font-size:13px;color:#e2e8f0'>✓ 200+ entegrasyon</div></div></div></div>`;
  else if (s.type === 'setup') content = `<div class='slide'><div class='slide-emoji'>${s.emoji}</div><div class='slide-title'>${s.title}</div><div class='slide-desc'>${s.desc}</div><div class='slide-visual'><div class='setup-form'><div><label>AD SOYAD</label><input placeholder='Ahmet Yılmaz'></div><div><label>ŞİRKET</label><input placeholder='TechVision A.Ş.'></div><div><label>ROL</label><select><option>Developer</option><option>Designer</option><option>Manager</option><option>Diğer</option></select></div></div></div></div>`;
  else if (s.type === 'features') content = `<div class='slide'><div class='slide-emoji'>${s.emoji}</div><div class='slide-title'>${s.title}</div><div class='slide-desc'>${s.desc}</div><div class='slide-visual'><div class='feature-grid'>${features.map(f=>`<div class='feature-item' onclick='this.classList.toggle("selected")'><div class='fi-emoji'>${f.emoji}</div><div class='fi-title'>${f.title}</div><div class='fi-desc'>${f.desc}</div></div>`).join('')}</div></div></div>`;
  else content = `<div class='slide'><div class='slide-emoji'>${s.emoji}</div><div class='slide-title'>${s.title}</div><div class='slide-desc'>${s.desc}</div><div class='slide-visual'><div class='success-checks'><div class='sc-item'><div class='sc-check'>✓</div>Profilin oluşturuldu</div><div class='sc-item'><div class='sc-check'>✓</div>Tercihler kaydedildi</div><div class='sc-item'><div class='sc-check'>✓</div>Hesabın aktif!</div></div></div></div>`;
  document.getElementById('slides').innerHTML = content;
  document.getElementById('back-btn').style.visibility = current > 0 ? 'visible' : 'hidden';
  document.getElementById('next-btn').textContent = current === steps.length-1 ? '🚀 Başla!' : 'Devam →';
  renderDots();
}
function next() { if (current < steps.length-1) { current++; renderSlide(); } else alert('Hoş geldin! Dashboard\'a yönlendiriliyorsun...'); }
function prev() { if (current > 0) { current--; renderSlide(); } }
renderSlide();
